            ExerciseItem(prompt: "Պատճառ. Վարորդը խաչմերուկում անցավ լուսացույցի կարմիր լույսի տակով մեծ արագությամբ։", options: ["Ճանապարհային ոստիկանությունը կանգնեցրեց նրան և խոշոր տուգանք նշանակեց", "Նա քաղաքապետարանի կողմից ստացավ տարվա օրինակելի վարորդի մրցանակ", "Մյուս մեքենաները ավտոմատ կերպով հետ քաշվեցին նրան ճանապարհ տալու համար", "Լուսացույցը անմիջապես կանաչեց, հենց նա մոտեցավ"], correctAnswer: "Ճանապարհային ոստիկանությունը կանգնեցրեց նրան և խոշոր տուգանք նշանակեց", explanation: "Կարմիր լույսի տակով անցնելը ճանապարհային երթևեկության կանոնների կոպիտ խախտում է, որը տուգանվում է։"),
            ExerciseItem(prompt: "Պատճառ. Քաղաքի ջրահեռացման համակարգը ամբողջությամբ խցանվել էր աղբի պատճառով։", options: ["Ուժեղ անձրևից հետո փողոցները հեղեղվեցին ջրով", "Անձրևաջրերը հեշտությամբ հոսեցին դեպի մոտակա գետը", "Քաղաքի փողոցները մնացին լիովին չոր և մաքուր", "Շշալցված հանքային ջրի գինը կտրուկ բարձրացավ խանութներում"], correctAnswer: "Ուժեղ անձրևից հետո փողոցները հեղեղվեցին ջրով", explanation: "Խցանված ջրահեռացման պատճառով անձրևաջրերը չեն կարողանում հեռանալ, ինչը հանգեցնում է փողոցների հեղեղմանը։"),
            ExerciseItem(prompt: "Հետևանք. Քննության արդյունքները տեսնելուց հետո Արամը շատ ուրախացավ և տոնեց ընտանիքի հետ։", options: ["Պատճառ. Նա ստացել էր ամենաբարձր գնահատականը և ընդունվել համալսարան", "Պատճառ. Նա չէր ներկայացել քննությանը ծանր հիվանդության պատճառով", "Պատճառ. Նա պատասխանների թերթիկը դատարկ էր թողել՝ ոչինչ չգրելով", "Պատճառ. Կազմկոմիտեն քննությունը հետաձգել էր անորոշ ժամանակով"], correctAnswer: "Պատճառ. Նա ստացել էր ամենաբարձր գնահատականը և ընդունվել համալսարան", explanation: "Քննությունից բարձր գնահատական ստանալը տրամաբանական պատճառն է ուրախության և տոնակատարության։"),
            ExerciseItem(prompt: "Հետևանք. Այս տարի ցորենի բերքը առատ էր, և ֆերմերները մեծ եկամուտ ստացան։", options: ["Պատճառ. Եղանակը բարենպաստ էր՝ անձրևները տեղացին ճիշտ ժամանակին", "Պատճառ. Ամբողջ տարվա ընթացքում երկրում տիրում էր սաստիկ երաշտ", "Պատճառ. Ֆերմերները օգտագործել էին կեղծված և անորակ պարարտանյութեր", "Պատճառ. Վայրի կենդանիները ոչնչացրել էին ցանքատարածությունների մեծ մասը"], correctAnswer: "Պատճառ. Եղանակը բարենպաստ էր՝ անձրևները տեղացին ճիշտ ժամանակին", explanation: "Բարենպաստ եղանակը և անձրևները ապահովում են լավ բերքատվություն գյուղատնտեսության մեջ։"),
            ExerciseItem(prompt: "Պատճառ. Ուսանողները ամբողջ գիշեր սովորել էին վերջնական քննության համար։", options: ["Առավոտյան նրանք զգում էին հոգնածություն և դժվարությամբ արթնացան", "Նրանք արթնացան շատ վաղ՝ լի էներգիայով և ուժով", "Դպրոցը հանկարծակի չեղարկեց այդ օրվա քննությունը", "Քննության ժամանակ նրանց միտքը չափազանց կենտրոնացած էր ու ակտիվ"], correctAnswer: "Առավոտյան նրանք զգում էին հոգնածություն և դժվարությամբ արթնացան", explanation: "Գիշերային անքնությունը հանգեցնում է առավոտյան հոգնածության և թուլության։"),
            ExerciseItem(prompt: "Պատճառ. Շուկայում լոլիկի առաջարկը չափազանց մեծացավ։", options: ["Լոլիկի մանրածախ գինը շուկայում զգալիորեն նվազեց", "Այլևս հնարավոր չէր լոլիկ գտնել տեղական խանութներում", "Լոլիկի արժեքը հասավ պատմական ամենաբարձր ցուցանիշին", "Կարտոֆիլի գինը կտրուկ բարձրացավ լոլիկի հետ միասին"], correctAnswer: "Լոլիկի մանրածախ գինը շուկայում զգալիորեն նվազեց", explanation: "Ըստ շուկայական օրենքի՝ երբ ապրանքի առաջարկը մեծանում է, դրա գինը նվազում է։"),
            ExerciseItem(prompt: "Հետևանք. Ամբողջ թաղամասը հայտնվեց խավարի մեջ, և շենքերի վերելակները կանգնեցին։", options: ["Պատճառ. Թաղամասի գլխավոր էլեկտրական տրանսֆորմատորը պայթեց", "Պատճառ. Կեսօր էր, և արևը պայծառ շողում էր երկնքում", "Պատճառ. Բնակիչները տանը սովորական լամպերը փոխարինել էին LED լամպերով", "Պատճառ. Շենքի կառավարումը բնակիչներին ազատեց այդ ամսվա վճարից"], correctAnswer: "Պատճառ. Թաղամասի գլխավոր էլեկտրական տրանսֆորմատորը պայթեց", explanation: "Գլխավոր տրանսֆորմատորի խափանումը հանգեցնում է էլեկտրականության անջատման և վերելակների կանգնեցման։"),
            ExerciseItem(prompt: "Պատճառ. Թոշակառուն սկսեց ամեն օր առավոտյան վազել և յոգայով զբաղվել։", options: ["Նրա ֆիզիկական պատրաստվածությունը և հոգեկան վիճակը զգալիորեն բարելավվեցին", "Նրա մարմինը թուլացավ, և նա սկսեց հաճախ հիվանդանալ", "Նրա քաշը մի քանի շաբաթվա ընթացքում ավելացավ քսան կիլոգրամով", "Նա կորցրեց քունը և սկսեց տառապել գիշերային անքնությունից"], correctAnswer: "Նրա ֆիզիկական պատրաստվածությունը և հոգեկան վիճակը զգալիորեն բարելավվեցին", explanation: "Ֆիզիկական ակտիվությունը և յոգան բարելավում են ընդհանուր առողջությունը և տրամադրությունը։"),
            ExerciseItem(prompt: "Պատճառ. Կառավարությունը օրենքով արգելեց միանգամյա օգտագործման պլաստիկ տոպրակների կիրառումը։", options: ["Քաղաքացիները սկսեցին գնումների գնալ կտորե բազմակի օգտագործման պարկերով", "Փողոցներում պլաստիկ աղբի քանակը ավելի շատացավ", "Գործարանները կրկնապատկեցին պլաստիկ տոպրակների արտադրությունը", "Խանութպանները անվճար և առատորեն բաժանեցին պլաստիկ տոպրակներ"], correctAnswer: "Քաղաքացիները սկսեցին գնումների գնալ կտորե բազմակի օգտագործման պարկերով", explanation: "Պլաստիկ տոպրակների արգելքը մարդկանց մղում է օգտագործել էկոլոգիապես մաքուր կտորե պարկեր։"),
            ExerciseItem(prompt: "Հետևանք. Սեղանին բաց թողնված թարմ կաթը թթվեց և փչացավ։", options: ["Պատճառ. Կաթը չէին դրել սառնարանում՝ թողնելով սենյակային տաք ջերմաստիճանում", "Պատճառ. Կաթը խնամքով պահվել էր սառնարանի ներսում", "Պատճառ. Մեկ թեյի գդալ շաքարավազ էր ավելացվել կաթի բաժակի մեջ", "Պատճառ. Կաթը թարմ կերպով բերվել էր ֆերմայից հենց այդ առավոտյան"], correctAnswer: "Պատճառ. Կաթը չէին դրել սառնարանում՝ թողնելով սենյակային տաք ջերմաստիճանում", explanation: "Տաք միջավայրում կաթը արագ է թթվում բակտերիաների բազմացման պատճառով։"),
            ExerciseItem(prompt: "Պատճառ. Ուժեղ քամին անցյալ տարի ոչնչացրեց լոբու ցանքատարածությունները երկրի հարավում։", options: ["Լոբու վաճառքի գինը ներքին շուկայում զգալիորեն թանկացավ", "Շուկայում լոբու ավելցուկ առաջացավ՝ ստիպելով պետությանը իջեցնել գները", "Ռեկորդային բերքը թույլ տվեց ավելի շատ լոբի արտահանել", "Սպառողները դադարեցին լոբի ուտել և օգտագործեցին միայն մակարոնեղեն"], correctAnswer: "Լոբու վաճառքի գինը ներքին շուկայում զգալիորեն թանկացավ", explanation: "Բերքի կորուստը նվազեցնում է առաջարկը շուկայում, ինչը հանգեցնում է գների բարձրացմանը։"),
            ExerciseItem(prompt: "Հետևանք. Հեռախոսի էկրանը հանկարծ հանգավ, և սարքն ինքնուրույն անջատվեց։", options: ["Պատճառ. Օգտատերը ամբողջ օրը ֆիլմեր էր դիտել առանց լիցքավորիչը միացնելու", "Պատճառ. Հեռախոսը ամբողջ գիշեր միացված էր օրիգինալ լիցքավորիչին", "Պատճառ. Սարքը մի քանի օր անջատված վիճակում պահվել էր դարակի մեջ", "Պատճառ. Օգտատերը փակել էր ֆոնային հավելվածները և միացրել խնայողության ռեժիմը"], correctAnswer: "Պատճառ. Օգտատերը ամբողջ օրը ֆիլմեր էր դիտել առանց լիցքավորիչը միացնելու", explanation: "Ակտիվ օգտագործումը (ֆիլմերի դիտումը) արագորեն սպառում է մարտկոցի լիցքը՝ անջատելով հեռախոսը։"),
