            ExerciseItem(prompt: "Թաց հագուստները արագ չորացնելու համար տատիկը բոլոր իրերը տեղադրեց սառը ջրով լի դույլի մեջ։", options: ["Հագուստը ջրի մեջ ընկղմելը մեծացնում է խոնավությունը և խոչընդոտում չորացմանը", "Թաց հագուստը չորանում է միայն լիովին փակ պահարանում կախված վիճակում", "Սառը ջուրը ամբողջությամբ քայքայում է հագուստի նեյլոնե թելերը", "Չորացման համար անհրաժեշտ է հագուստի վրա լցնել ջուր կլանող նանո փոշի"], correctAnswer: "Հագուստը ջրի մեջ ընկղմելը մեծացնում է խոնավությունը և խոչընդոտում չորացմանը", explanation: "Չորացումը ջրի գոլորշիացումն է նյութից. հագուստը ջրի մեջ դնելը ավելի է թրջում այն։"),
            ExerciseItem(prompt: "Ավտոբուսի վարորդը, ոլորանի վրա արագությունը մեծացնելու համար, ուժգին սեղմեց արգելակման ոտնակը։", options: ["Արգելակը դանդաղեցնում կամ կանգնեցնում է մեքենան, այլ ոչ թե մեծացնում արագությունը", "Մեքենան դանդաղում է միայն այն դեպքում, երբ ղեկը կտրուկ աջ ու ձախ ես պտտում", "Մեծ մեքենաների արգելակը տեղադրված է միայն ուղևորի նստատեղի կողմում", "Արգելակումը անմիջապես գոլորշիացնում է դիզվառելիքը բաքից"], correctAnswer: "Արգելակը դանդաղեցնում կամ կանգնեցնում է մեքենան, այլ ոչ թե մեծացնում արագությունը", explanation: "Արգելակման ոտնակը նախատեսված է արագությունը նվազեցնելու համար. արագացման համար օգտագործվում է գազի ոտնակը։"),
            ExerciseItem(prompt: "Որորները սուզվեցին հարյուրավոր մետրեր օվկիանոսի հատակը և չոր ճյուղերից տաք բույն հյուսեցին ձվադրելու համար։", options: ["Որորները շնչում են թոքերով և չեն կարող ապրել կամ բույն հյուսել ջրի տակ", "Որորները իրենց բույնը հյուսում են միայն ամպերի վրա ձագեր հանելու համար", "Օվկիանոսի խորքում ջուրը միշտ եռում է 100 աստիճանից բարձր", "Թռչունների փետուրները ջրի տակ ենթարկվում են ինքնաբռնկման"], correctAnswer: "Որորները շնչում են թոքերով և չեն կարող ապրել կամ բույն հյուսել ջրի տակ", explanation: "Թռչունները թոքերով շնչող էակներ են և կխեղդվեն ջրի տակ, իսկ ջրի հոսանքը կքանդի չոր ճյուղերը։"),
            ExerciseItem(prompt: "Տղան փորձեց օջախին եռացող բանջարեղենային ապուրը և դժգոհ դեմքով ասաց. «Այս ապուրը սառը է սառույցի պես»։", options: ["Եռացող ապուրն ունի շատ բարձր ջերմաստիճան և այրում է բերանը, այն չի կարող սառը լինել", "Բանջարեղենային ապուրը պետք է ուտել փայտե գդալով ջերմությունը ճիշտ զգալու համար", "Չափազանց տաք սնունդը անմիջապես և ընդմիշտ անզգայացնում է լեզուն", "Եռացող հեղուկները վերածվում են սառույցի կրակը անջատելու պահին"], correctAnswer: "Եռացող ապուրն ունի շատ բարձր ջերմաստիճան և այրում է բերանը, այն չի կարող սառը լինել", explanation: "Ջուրը և ապուրը եռում են մոտ 100 աստիճանում. այն համտեսելիս այրում է լեզուն, ոչ թե սառեցնում։"),
            ExerciseItem(prompt: "Տան դուռը ամուր փակելու համար հայրը բանալին նետեց դռան անցքով դեպի արտաքին այգի։", options: ["Փականը փակելու համար անհրաժեշտ է բանալին մուտքագրել միջուկի մեջ և պտտել, ոչ թե նետել", "Դռան փոքր անցքը թույլ չի տա բանալուն անցնել դրա միջով", "Փայտե դռները պետք է փակել միայն բամբուկե մեծ նիգերով", "Զրահապատ դռները փակվում են միայն աչքի ցանցաթաղանթի սկանավորմամբ"], correctAnswer: "Փականը փակելու համար անհրաժեշտ է բանալին մուտքագրել միջուկի մեջ և պտտել, ոչ թե նետել", explanation: "Դուռը կողպելու համար բանալին պետք է տեղադրվի կողպեքի գլանի մեջ և պտտվի՝ մեխանիզմը շարժելու համար։"),
            ExerciseItem(prompt: "Կույր մարդը վերցրեց աստղադիտակը և մանրամասն նկարագրեց հեռավոր բլրի վրա աճող կարմիր ծաղիկները։", options: ["Կույրը չունի տեսողություն աստղադիտակի պատկերները ընկալելու համար", "Աստղադիտակը նախատեսված է միայն տիեզերագնացների համար այլ մոլորակներ դիտելու", "Հեռավոր բլուրների վրա աճում են միայն փշոտ կակտուսներ", "Աստղադիտակը ցերեկային լույսի տակ ընդհանրապես չի մեծացնում պատկերները"], correctAnswer: "Կույրը չունի տեսողություն աստղադիտակի պատկերները ընկալելու համար", explanation: "Կուրությունը նշանակում է տեսողական ֆունկցիայի բացակայություն. խոշորացնող լինզաները չեն կարող փոխարինել աչքի տեսողությանը։"),
            ExerciseItem(prompt: "Պատի ժամացույցի վայրկյանացույցը սկսեց պտտվել հակառակ ուղղությամբ, ինչի պատճառով իրական ժամանակը հետ գնաց դեպի երեկ։", options: ["Ժամացույցը միայն չափիչ սարք է, և սլաքների պտույտը չի փոխում իրական ժամանակի ընթացքը", "Սլաքի հակառակ պտտվելը պայթեցնում է մարտկոցները տեղում", "Ժամանակը ավելի արագ է ընթանում տիեզերանավով վակուումում ճանապարհորդելիս", "Սլաքները աշխատում են էլեկտրամագնիսական կոճերով, որոնք կանխում են հետընթացը"], correctAnswer: "Ժամացույցը միայն չափիչ սարք է, և սլաքների պտույտը չի փոխում իրական ժամանակի ընթացքը", explanation: "Ժամանակը ֆիզիկական չափում է, որն ընթանում է միայն առաջ. ժամացույցի սլաքները հետ տանելը չի ազդում իրական ժամանակի վրա։"),
            ExerciseItem(prompt: "Նա գրեց լիովին թաց թղթի վրա չոր գնդիկավոր գրիչով և ստացավ շատ մաքուր ու կոկիկ ձեռագիր։", options: ["Թաց թուղթը հեշտությամբ պատռվում է, իսկ գրիչի թանաքը տարածվում է ջրի մեջ", "Թաց թղթի վրա կարելի է գրել միայն յուղաներկ վրձնով ջրի տակ", "Գնդիկավոր գրիչները գրում են միայն փայլեցված ոսկե սալիկների վրա", "Թղթի խոնավությունը գոլորշիանում է գրիչի ծայրի շփման ջերմությունից անմիջապես"], correctAnswer: "Թաց թուղթը հեշտությամբ պատռվում է, իսկ գրիչի թանաքը տարածվում է ջրի մեջ", explanation: "Ջուրը թուլացնում է թղթի մանրաթելերը, և գրիչի սուր ծայրը պատռում է այն, իսկ թանաքը լուծվում է ջրում և լղոզվում։")
        ]
    )

